(()=>{'use strict';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH');
const $=s=>document.querySelector(s);
const sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});
let rawPayload=null,rawRows=[],meta={};
function rowsOf(p){return p?.rows||p||[]}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function scope(){const c=window.DOIT_APP_COORDINATOR?.getScope?.();return c||{dates:[...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))],ps:[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))],dateKey:T(window.DOIT_SELECTED_DATE_KEY),psKey:T(window.DOIT_SELECTED_PS_KEY),receiver:T($('#storeSelect')?.value)}}
function appKey(){return T(meta.id||meta.version_id||rawPayload?.version_id||meta.file_name||'active')}
function keys(prefix){const out=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i)||'';if(k.startsWith(prefix))out.push(k)}return out}
function stateKeys(){const k=appKey();const preferred=k&&k!=='active'?'doit-json:'+k:'';const all=keys('doit-json:');return preferred?[preferred,...all.filter(x=>x!==preferred)]:all}
function manualKeys(){const k=appKey();const preferred=k&&k!=='active'?'doit-manual-v1:'+k:'';const all=keys('doit-manual-v1:');return preferred?[preferred,...all.filter(x=>x!==preferred)]:all}
function historyKeys(){const k=appKey();const preferred=k&&k!=='active'?'doit-print-history-v1:'+k:'';const all=keys('doit-print-history-v1:');return preferred?[preferred,...all.filter(x=>x!==preferred)]:all}
function read(k,d){try{return JSON.parse(localStorage.getItem(k)||'')||d}catch{return d}}
function pk(r){return[T(r.brand),T(r.size),T(r.code||r.sku),T(r.sku),T(r.type||'INVC')].join('|')}
function pkFromData(x){if(x.poolKey)return x.poolKey;if(x.manual)return['MANUAL',x.id||'',x.store||'',x.brand||'',x.code||'',x.name||x.sku||'',x.type||''].join('|');const name=T(x.name||x.sku);return[x.brand||'',x.size||'',x.code||name,name,x.type||''].join('|')}
function pkFromStateKey(k){return String(k).split('|').slice(6).join('|')||String(k).split('|').slice(4).join('|')}
function recFromStateKey(k){return String(k).split('|')[5]||String(k).split('|')[3]||''}
function dateOk(r,sc){return !sc.dates?.length||sc.dates.includes(T(r.date))}
function psOk(r,sc){return !sc.ps?.length||sc.ps.includes(cleanPs(r.ps))}
function histOk(h,sc){if(sc.dateKey&&h.dateKey)return h.dateKey===sc.dateKey;if(sc.dates?.length&&h.start&&h.end)return sc.dates.some(d=>d>=h.start&&d<=h.end);if(sc.dates?.length&&h.start)return sc.dates.includes(h.start);return true}
function histPsOk(h,sc){if(sc.psKey&&h.psKey)return h.psKey===sc.psKey;if(sc.ps?.length&&h.ps)return sc.ps.includes(cleanPs(h.ps));return true}
function manualOk(x,sc){if(sc.receiver&&x.store!==sc.receiver)return false;if(sc.dateKey&&x.dateKey)return x.dateKey===sc.dateKey;if(sc.dates?.length&&x.start&&x.end&&!sc.dates.some(d=>d>=x.start&&d<=x.end))return false;if(sc.dates?.length&&x.start&&!sc.dates.includes(x.start))return false;if(sc.psKey&&x.psKey)return x.psKey===sc.psKey;if(sc.ps?.length&&x.ps&&!sc.ps.includes(cleanPs(x.ps)))return false;return true}
function add(map,k,n){map.set(k,(map.get(k)||0)+N(n))}
function addStore(stores,k,store,qty){store=T(store)||'ไม่ระบุร้าน';if(!stores.has(k))stores.set(k,new Map());const m=stores.get(k);m.set(store,(m.get(store)||0)+N(qty))}
function setLabel(labels,k,x){if(!labels.has(k))labels.set(k,{key:k,brand:T(x.brand),size:T(x.size),code:T(x.code),name:T(x.sku||x.name)||k,type:T(x.type),manual:!!x.manual})}
function build(){const sc=scope(),order=new Map(),sent=new Map(),stores=new Map(),labels=new Map();rawRows.filter(r=>!realTele(r)&&dateOk(r,sc)&&psOk(r,sc)).forEach(r=>{const k=pk(r);add(order,k,r.qty);setLabel(labels,k,r)});historyKeys().forEach(hk=>read(hk,[]).forEach(h=>{if(!histOk(h,sc)||!histPsOk(h,sc))return;(h.items||[]).forEach(x=>{if(sc.receiver&&(x.store||h.store)!==sc.receiver)return;const k=pkFromData(x);add(sent,k,x.qty);addStore(stores,k,x.store||h.store,x.qty);setLabel(labels,k,{...x,sku:x.name||x.sku})})}));stateKeys().forEach(sk=>{const st=read(sk,{}),send=st.send||{};Object.keys(send).forEach(key=>{const qty=N(send[key]);if(qty<=0)return;const p=String(key).split('|'),legacy={start:p[0],end:p[1],ps:p[2],store:p[3]},newer={start:p[0],end:p[1],ps:p[2],store:p[5]};const store=recFromStateKey(key);if(sc.receiver&&store!==sc.receiver)return;if(sc.dates?.length&&legacy.start&&legacy.end&&!sc.dates.some(d=>d>=legacy.start&&d<=legacy.end))return;if(sc.ps?.length&&legacy.ps&&!sc.ps.includes(cleanPs(legacy.ps)))return;const k=pkFromStateKey(key);add(sent,k,qty);addStore(stores,k,store,qty)})});manualKeys().forEach(mk=>read(mk,[]).filter(x=>manualOk(x,sc)).forEach(x=>{const k=pkFromData({...x,manual:true});add(sent,k,x.qty);addStore(stores,k,x.store,x.qty);setLabel(labels,k,{...x,sku:x.name,manual:true})}));const all=new Set([...order.keys(),...sent.keys()]);return[...all].map(k=>{const l=labels.get(k)||{key:k,name:k,brand:'',size:'',code:'',type:''};const keyed=N(order.get(k)),sentQty=N(sent.get(k)),remain=keyed-sentQty;const storeText=[...(stores.get(k)||new Map()).entries()].filter(([,q])=>N(q)).sort((a,b)=>sorter.compare(a[0],b[0])).map(([s,q])=>`${s} ${F(q)}`).join(', ');return{...l,keyed,sent:sentQty,stores:storeText||'-',remain}}).sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.name,b.name))}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function csv(data){const out=[['ชื่อสินค้า','จำนวนคีย์','ร้านที่ส่ง','ของเหลือ']];data.forEach(r=>out.push([r.name,r.keyed,r.stores,r.remain]));const blob='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([blob],{type:'text/csv;charset=utf-8'}));a.download='doit-remaining-summary-v291.csv';a.click()}
function css(){if($('#remainCoordinatorCss291'))return;const st=document.createElement('style');st.id='remainCoordinatorCss291';st.textContent='#remainOverlay291{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:9998;display:flex;align-items:flex-end}#remainPanel291{background:#fff;width:100%;max-height:88vh;border-radius:18px 18px 0 0;overflow:auto;color:#111827}#remainHead291{position:sticky;top:0;background:#087b34;color:#fff;padding:10px 12px;display:flex;justify-content:space-between;gap:8px;align-items:center}#remainHead291 button{height:34px;border:1px solid #fff;background:#fff;color:#087b34;border-radius:8px;font-weight:900;padding:0 10px}.remainNote291{padding:10px;color:#4b5563;font-size:12px}.remainWrap291{overflow:auto;padding:0 10px 12px}.remainTbl291{width:100%;border-collapse:collapse;min-width:760px;font-size:12px}.remainTbl291 th,.remainTbl291 td{border:1px solid #e5e7eb;padding:7px;text-align:center}.remainTbl291 th{background:#f8fafc}.remainTbl291 td:nth-child(1),.remainTbl291 th:nth-child(1),.remainTbl291 td:nth-child(3),.remainTbl291 th:nth-child(3){text-align:left}.remainNeg{color:#dc2626;font-weight:950}.remainPos{color:#111827;font-weight:900}.remainZero{color:#15803d;font-weight:900}@media(max-width:640px){.remainTbl291{min-width:680px}}';document.head.appendChild(st)}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function openSummary(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();css();$('#remainOverlay')?.remove();$('#remainOverlay291')?.remove();const data=build(),sc=scope();const dateTxt=sc.dates?.length?sc.dates.map(thai).join(', '):'ทุกวัน';const psTxt=sc.ps?.length?sc.ps.join(', '):'ทั้งหมด';const ov=document.createElement('div');ov.id='remainOverlay291';ov.innerHTML=`<section id="remainPanel291"><div id="remainHead291"><div><b>สรุปของเหลือ V2.9.1</b><br><small>วันที่ ${esc(dateTxt)} · PS ${esc(psTxt)} · ร้าน ${esc(sc.receiver||'ทั้งหมด')} · ไม่รวม Telesale</small></div><span><button id="remainCsv291">Export</button> <button id="remainClose291">ปิด</button></span></div><div class="remainNote291">ของเหลือ = จำนวนคีย์ - จำนวนที่ส่ง/ปิดบิล/ค้างส่ง. ถ้าส่งเกินจะแสดงติดลบสีแดง เช่น -1</div><div class="remainWrap291"><table class="remainTbl291"><thead><tr><th>ชื่อสินค้า</th><th>จำนวนคีย์</th><th>ร้านที่ส่ง</th><th>ของเหลือ</th></tr></thead><tbody>${data.map(r=>`<tr><td>${esc(r.name)}<br><small>${esc(r.code||'')}</small></td><td>${F(r.keyed)}</td><td>${esc(r.stores)}</td><td class="${r.remain<0?'remainNeg':(r.remain===0?'remainZero':'remainPos')}">${F(r.remain)}</td></tr>`).join('')||'<tr><td colspan="4">ไม่พบข้อมูล</td></tr>'}</tbody></table></div></section>`;document.body.appendChild(ov);$('#remainClose291').onclick=()=>ov.remove();$('#remainCsv291').onclick=()=>csv(data);ov.onclick=x=>{if(x.target===ov)ov.remove()}}
function install(){let b=$('#remainSummaryBtn');if(b){b.onclick=null;b.addEventListener('click',openSummary,true);b.textContent='สรุปของเหลือ';return}const a=document.querySelector('.actions');if(a){b=document.createElement('button');b.id='remainSummaryBtn';b.type='button';b.className='outline';b.textContent='สรุปของเหลือ';b.addEventListener('click',openSummary,true);a.prepend(b)}}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__remainCoord291)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{rawPayload=payload;meta=m||{};const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length>=rawRows.length)rawRows=arr.map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));const res=old(payload,m);setTimeout(install,100);return res};app.__remainCoord291=true;return true}
function boot(){install();patchLoad();let n=0;const tick=()=>{install();patchLoad();if(++n<12)setTimeout(tick,500)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();